1→/*
     2→ * HoloCanvas – Ledger Core
     3→ * Module  : Delegated-Artistry (DA) Consensus Strategy
     4→ * File    : strategies/da_strategy.c
     5→ *
     6→ * Copyright (c) 2024 HoloCanvas.
     7→ *
     8→ * Description:
     9→ *   This file implements the “Delegated-Artistry” consensus strategy used by
    10→ *   the Ledger-Core micro-service.  DA is a delegated Proof-of-Stake variant
    11→ *   optimised for collaborative, generative-art workloads.  Curators delegate
    12→ *   “inspiration weight” to trusted validator nodes (“Art Directors”),
    13→ *   incentivising rapid block finality while preserving decentralisation by
    14→ *   periodically rotating directors via on-chain votes.
    15→ *
    16→ *   The implementation follows the Strategy Pattern.  The generic consensus
    17→ *   engine (consensus_engine.c) calls the function pointers exposed in
    18→ *   consensus_strategy_t.  Swapping between DA and alternative strategies
    19→ *   (e.g., PoS-Staking) therefore requires no changes in the core engine.
    20→ *
    21→ *   NOTE: This module purposefully avoids direct networking / I/O.  All such
    22→ *   side-effects are decoupled through event queues (Kafka) or gRPC calls
    23→ *   marshalled by other Ledger-Core components.
    24→ */
    25→
    26→#include <errno.h>
    27→#include <inttypes.h>
    28→#include <pthread.h>
    29→#include <stdatomic.h>
    30→#include <stdbool.h>
    31→#include <stdio.h>
    32→#include <stdlib.h>
    33→#include <string.h>
    34→#include <time.h>
    35→
    36→#include "crypto/sha3.h"              /* Lightweight SHA-3 wrapper          */
    37→#include "crypto/signatures.h"        /* Ed25519/ZKP signatures             */
    38→#include "event_bus/event_bus.h"      /* Internal event bus abstraction     */
    39→#include "ledger/block.h"             /* Canonical block representation     */
    40→#include "ledger/state.h"             /* World-state API                    */
    41→#include "ledger/tx_pool.h"           /* Transaction pool                   */
    42→#include "log/log.h"                  /* Structured logging                 */
    43→#include "strategies/da_strategy.h"   /* Public header for this module      */
    44→
    45→/* ------------------------------------------------------------------------- *
    46→ * Constants / Macros
    47→ * ------------------------------------------------------------------------- */
    48→#define DA_MAX_DIRECTORS           128U   /* Hard cap on active directors   */
    49→#define DA_EPOCH_LENGTH            600U   /* Blocks per epoch               */
    50→#define DA_MIN_STAKE              1000U   /* Minimum “inspiration” stake    */
    51→#define DA_REWARD_BASE_PERCENT        2   /* 2 % base block reward          */
    52→#define DA_MAX_SLASH_PERCENT          5   /* 5 % maximum slashing           */
    53→
    54→/* For compact, canonicalised hashing */
    55→#define HASH_STR_LEN                65U   /* Hex(32-byte) + NUL             */
    56→
    57→/* ------------------------------------------------------------------------- *
    58→ * Internal Data Structures
    59→ * ------------------------------------------------------------------------- */
    60→
    61→/* Forward declaration */
    62→typedef struct da_strategy_ctx        da_strategy_ctx_t;
    63→
    64→/*
    65→ * Director (validator) metadata — persisted to the world-state but cached
    66→ * locally for hot-path operations.
    67→ */
    68→typedef struct
    69→{
    70→    uint8_t        pubkey[ED25519_PUBKEY_LEN];
    71→    uint64_t       stake;                 /* Total delegated inspiration   */
    72→    uint64_t       last_signed;           /* Last block height signed      */
    73→    uint32_t       missed_blocks;         /* Counter for missed signatures */
    74→    bool           jailed;                /* Temporarily banned            */
    75→} da_director_t;
    76→
    77→/*
    78→ * Epoch snapshot — recalculated every DA_EPOCH_LENGTH blocks.
    79→ */
    80→typedef struct
    81→{
    82→    size_t           num_directors;
    83→    da_director_t    directors[DA_MAX_DIRECTORS];
    84→    uint64_t         total_stake;         /* Σ stake for director set      */
    85→    uint64_t         epoch_index;         /* Monotonic epoch counter       */
    86→} da_epoch_t;
    87→
    88→/*
    89→ * Main strategy context.  Thread-safe via internal RW-lock.
    90→ */
    91→struct da_strategy_ctx
    92→{
    93→    pthread_rwlock_t  rwlock;             /* Protects mutable state        */
    94→    da_epoch_t        current_epoch;
    95→    atomic_uint_least64_t  height;        /* Latest committed block height */
    96→    event_bus_t      *bus;                /* Local ref to event bus        */
    97→    state_ctx_t      *state;              /* Global world-state handle     */
    98→    tx_pool_t        *tx_pool;            /* Reference to transaction pool */
    99→    da_config_t       cfg;                /* Immutable configuration       */
   100→};
   101→
   102→/* ------------------------------------------------------------------------- *
   103→ * Static Helper Prototypes
   104→ * ------------------------------------------------------------------------- */
   105→static bool      da_recalc_epoch_if_needed(da_strategy_ctx_t *ctx,
   106→                                           uint64_t new_height);
   107→static bool      da_select_leader(const da_strategy_ctx_t *ctx,
   108→                                  uint64_t height,
   109→                                  da_director_t *out);
   110→static uint64_t  da_calc_block_reward(const da_strategy_ctx_t *ctx,
   111→                                      const da_director_t    *leader);
   112→static void      da_apply_slash(da_strategy_ctx_t *ctx,
   113→                                da_director_t     *offender,
   114→                                uint32_t           percent);
   115→static void      da_log_director_set(const da_epoch_t *epoch);
   116→static int       da_compare_director(const void *a, const void *b);
   117→
   118→/* ------------------------------------------------------------------------- *
   119→ * Strategy API Implementation
   120→ * ------------------------------------------------------------------------- */
   121→
   122→static bool
   123→da_init(consensus_strategy_t *iface,
   124→        consensus_engine_t    *engine,
   125→        const void            *params,
   126→        size_t                 params_len)
   127→{
   128→    if (!iface || !engine) {
   129→        return false;
   130→    }
   131→
   132→    (void)params_len; /* Unused until we version-tag params */
   133→
   134→    const da_config_t *cfg = (const da_config_t *)params;
   135→    if (!cfg) {
   136→        LOG_ERROR("DA_STRATEGY: Missing configuration payload");
   137→        return false;
   138→    }
   139→
   140→    da_strategy_ctx_t *ctx = calloc(1, sizeof(*ctx));
   141→    if (!ctx) {
   142→        LOG_SYSERROR(errno, "DA_STRATEGY: Allocation failure");
   143→        return false;
   144→    }
   145→
   146→    if (pthread_rwlock_init(&ctx->rwlock, NULL) != 0) {
   147→        LOG_SYSERROR(errno, "DA_STRATEGY: RW-Lock init failed");
   148→        free(ctx);
   149→        return false;
   150→    }
   151→
   152→    ctx->bus   = engine->bus;
   153→    ctx->state = engine->state;
   154→    ctx->tx_pool = engine->tx_pool;
   155→    ctx->cfg   = *cfg;
   156→
   157→    /* Bootstrap from genesis state */
   158→    ctx->current_epoch.epoch_index  = 0;
   159→    ctx->current_epoch.total_stake  = 0;
   160→    ctx->current_epoch.num_directors = 0;
   161→
   162→    /* Fetch initial director set from world-state */
   163→    /* (Assume state_director_iterate exists) */
   164→    state_director_iter_t it;
   165→    state_director_iter_init(ctx->state, &it);
   166→    while (state_director_iter_next(&it)) {
   167→        const director_record_t *rec = state_director_iter_record(&it);
   168→        if (rec->stake < DA_MIN_STAKE) {
   169→            continue;
   170→        }
   171→        if (ctx->current_epoch.num_directors >= DA_MAX_DIRECTORS) {
   172→            LOG_WARN("DA_STRATEGY: Director set truncated to %u",
   173→                     DA_MAX_DIRECTORS);
   174→            break;
   175→        }
   176→
   177→        da_director_t *d =
   178→            &ctx->current_epoch.directors[ctx->current_epoch.num_directors++];
   179→        memcpy(d->pubkey, rec->pubkey, sizeof(d->pubkey));
   180→        d->stake         = rec->stake;
   181→        d->last_signed   = 0;
   182→        d->missed_blocks = 0;
   183→        d->jailed        = false;
   184→        ctx->current_epoch.total_stake += rec->stake;
   185→    }
   186→
   187→    state_director_iter_close(&it);
   188→
   189→    /* Sort directors deterministically for leader selection */
   190→    qsort(ctx->current_epoch.directors,
   191→          ctx->current_epoch.num_directors,
   192→          sizeof(da_director_t),
   193→          da_compare_director);
   194→
   195→    da_log_director_set(&ctx->current_epoch);
   196→
   197→    atomic_store(&ctx->height, 0);
   198→
   199→    /* Store ctx in the strategy interface’s opaque pointer */
   200→    iface->impl_ctx = ctx;
   201→    return true;
   202→}
   203→
   204→static void
   205→da_free(consensus_strategy_t *iface)
   206→{
   207→    if (!iface || !iface->impl_ctx) return;
   208→
   209→    da_strategy_ctx_t *ctx = iface->impl_ctx;
   210→
   211→    pthread_rwlock_destroy(&ctx->rwlock);
   212→    free(ctx);
   213→    iface->impl_ctx = NULL;
   214→}
   215→
   216→/*
   217→ * validate_block:
   218→ *   1. Enforce correct leader for height.
   219→ *   2. Verify signature.
   220→ *   3. Validate tx root & state transition via engine API.
   221→ */
   222→static bool
   223→da_validate_block(consensus_strategy_t *iface,
   224→                  const block_t        *blk,
   225→                  char                  err_buf[CONS_STRAT_ERRBUF_SZ])
   226→{
   227→    if (!iface || !blk) return false;
   228→
   229→    da_strategy_ctx_t *ctx = iface->impl_ctx;
   230→    bool ok = false;
   231→
   232→    pthread_rwlock_rdlock(&ctx->rwlock);
   233→
   234→    da_director_t expected_leader;
   235→    if (!da_select_leader(ctx, blk->header.height, &expected_leader)) {
   236→        snprintf(err_buf, CONS_STRAT_ERRBUF_SZ,
   237→                 "Failed to select leader for height %" PRIu64,
   238→                 blk->header.height);
   239→        goto exit;
   240→    }
   241→
   242→    if (memcmp(expected_leader.pubkey,
   243→               blk->header.proposer_pubkey,
   244→               sizeof(expected_leader.pubkey)) != 0)
   245→    {
   246→        snprintf(err_buf, CONS_STRAT_ERRBUF_SZ,
   247→                 "Block proposer not expected leader");
   248→        goto exit;
   249→    }
   250→
   251→    /* Verify proposer signature */
   252→    if (!sig_verify_ed25519(blk->header_hash,
   253→                            sizeof(blk->header_hash),
   254→                            blk->header.proposer_sig,
   255→                            expected_leader.pubkey))
   256→    {
   257→        snprintf(err_buf, CONS_STRAT_ERRBUF_SZ,
   258→                 "Invalid leader signature");
   259→        goto exit;
   260→    }
   261→
   262→    /* Additional validation deferred to engine (tx Merkle, receipts, etc.) */
   263→    ok = true;
   264→
   265→exit:
   266→    pthread_rwlock_unlock(&ctx->rwlock);
   267→    return ok;
   268→}
   269→
   270→/*
   271→ * apply_block:
   272→ *   Mutates strategy-specific state after the block has been committed to the
   273→ *   canonical chain (height → height+1).  This is the place to apply rewards,
   274→ *   re-calc epochs, slash misbehaviour, etc.
   275→ */
   276→static bool
   277→da_apply_block(consensus_strategy_t *iface, const block_t *blk)
   278→{
   279→    if (!iface || !blk) return false;
   280→
   281→    da_strategy_ctx_t *ctx = iface->impl_ctx;
   282→    bool               ok  = true;
   283→
   284→    pthread_rwlock_wrlock(&ctx->rwlock);
   285→
   286→    uint64_t new_height = blk->header.height;
   287→    atomic_store(&ctx->height, new_height);
   288→
   289→    /* Update last_signed for leader */
   290→    da_director_t leader;
   291→    if (da_select_leader(ctx, new_height, &leader)) {
   292→        leader.last_signed = new_height;
   293→        leader.missed_blocks = 0; /* Reset missed block counter */
   294→        /* Persist update to world-state asynchronously */
   295→        state_enqueue_director_update(ctx->state,
   296→                                      leader.pubkey,
   297→                                      leader.stake,
   298→                                      leader.missed_blocks,
   299→                                      leader.jailed);
   300→    }
   301→
   302→    /* Reward distribution */
   303→    uint64_t reward = da_calc_block_reward(ctx, &leader);
   304→    if (reward > 0) {
   305→        /* Mint reward to leader’s account; engine handles supply inflation */
   306→        state_credit_account(ctx->state, leader.pubkey, reward);
   307→    }
   308→
   309→    /* Epoch change? */
   310→    if (!da_recalc_epoch_if_needed(ctx, new_height)) {
   311→        ok = false;
   312→    }
   313→
   314→    pthread_rwlock_unlock(&ctx->rwlock);
   315→    return ok;
   316→}
   317→
   318→/* ------------------------------------------------------------------------- *
   319→ * Helper Implementations
   320→ * ------------------------------------------------------------------------- */
   321→
   322→static bool
   323→da_recalc_epoch_if_needed(da_strategy_ctx_t *ctx, uint64_t new_height)
   324→{
   325→    if ((new_height % DA_EPOCH_LENGTH) != 0) {
   326→        return true; /* Nothing to do */
   327→    }
   328→
   329→    uint64_t next_epoch_index = ctx->current_epoch.epoch_index + 1;
   330→    da_epoch_t next = {
   331→        .num_directors = 0,
   332→        .total_stake   = 0,
   333→        .epoch_index   = next_epoch_index
   334→    };
   335→
   336→    /* Collect candidate directors from world-state */
   337→    state_director_iter_t it;
   338→    state_director_iter_init(ctx->state, &it);
   339→
   340→    while (state_director_iter_next(&it))
   341→    {
   342→        const director_record_t *rec = state_director_iter_record(&it);
   343→
   344→        if (rec->stake < DA_MIN_STAKE || rec->jailed) {
   345→            continue;
   346→        }
   347→        if (next.num_directors >= DA_MAX_DIRECTORS) {
   348→            LOG_WARN("DA_STRATEGY: Director set truncated to %u", DA_MAX_DIRECTORS);
   349→            break;
   350→        }
   351→
   352→        da_director_t *d = &next.directors[next.num_directors++];
   353→        memcpy(d->pubkey, rec->pubkey, sizeof(d->pubkey));
   354→        d->stake         = rec->stake;
   355→        d->last_signed   = rec->last_signed;
   356→        d->missed_blocks = rec->missed_blocks;
   357→        d->jailed        = rec->jailed;
   358→        next.total_stake += rec->stake;
   359→    }
   360→    state_director_iter_close(&it);
   361→
   362→    /* If no directors, strategy cannot continue */
   363→    if (next.num_directors == 0) {
   364→        LOG_CRITICAL("DA_STRATEGY: No eligible directors for epoch %" PRIu64,
   365→                     next_epoch_index);
   366→        return false;
   367→    }
   368→
   369→    /* Sort deterministically */
   370→    qsort(next.directors,
   371→          next.num_directors,
   372→          sizeof(da_director_t),
   373→          da_compare_director);
   374→
   375→    ctx->current_epoch = next;
   376→    da_log_director_set(&ctx->current_epoch);
   377→
   378→    /* Emit event for observability */
   379→    event_bus_publish(ctx->bus, EVENT_EPOCH_CHANGED, &next, sizeof(next));
   380→
   381→    return true;
   382→}
   383→
   384→/*
   385→ * Deterministic leader selection using weighted-round-robin proportional to
   386→ * stake, salted by epoch index to prevent grinding.
   387→ */
   388→static bool
   389→da_select_leader(const da_strategy_ctx_t *ctx,
   390→                 uint64_t                 height,
   391→                 da_director_t           *out)
   392→{
   393→    if (ctx->current_epoch.num_directors == 0) {
   394→        return false;
   395→    }
   396→
   397→    uint64_t slot = height % ctx->current_epoch.num_directors;
   398→
   399→    /* SHA3(epoch||height) to produce pseudo-random permutation */
   400→    uint8_t seed_hash[SHA3_256_DIGEST_LEN];
   401→    uint8_t input[sizeof(uint64_t) * 2];
   402→    memcpy(input, &ctx->current_epoch.epoch_index, sizeof(uint64_t));
   403→    memcpy(input + sizeof(uint64_t), &height, sizeof(uint64_t));
   404→    sha3_256(seed_hash, sizeof(seed_hash), input, sizeof(input));
   405→
   406→    uint64_t rnd;
   407→    memcpy(&rnd, seed_hash, sizeof(rnd));
   408→    rnd %= ctx->current_epoch.num_directors;
   409→
   410→    size_t idx = (slot + rnd) % ctx->current_epoch.num_directors;
   411→
   412→    *out = ctx->current_epoch.directors[idx];
   413→    return true;
   414→}
   415→
   416→static uint64_t
   417→da_calc_block_reward(const da_strategy_ctx_t *ctx,
   418→                     const da_director_t     *leader)
   419→{
   420→    if (ctx->cfg.fixed_reward > 0) {
   421→        return ctx->cfg.fixed_reward;
   422→    }
   423→
   424→    /* Otherwise reward proportional to stake */
   425→    double pct = (double)DA_REWARD_BASE_PERCENT / 100.0;
   426→    double reward = (double)leader->stake * pct;
   427→    return (uint64_t)reward;
   428→}
   429→
   430→/*
   431→ * Slash a director by percentage of stake, jail if severe.
   432→ */
   433→static void
   434→da_apply_slash(da_strategy_ctx_t *ctx,
   435→               da_director_t     *offender,
   436→               uint32_t           percent)
   437→{
   438→    if (percent == 0 || percent > DA_MAX_SLASH_PERCENT) return;
   439→
   440→    uint64_t penalty = (offender->stake * percent) / 100;
   441→    offender->stake -= penalty;
   442→
   443→    state_debit_account(ctx->state, offender->pubkey, penalty);
   444→
   445→    LOG_WARN("DA_STRATEGY: Director slashed %" PRIu32 "%% (penalty=%" PRIu64 ")",
   446→             percent, penalty);
   447→
   448→    if (percent == DA_MAX_SLASH_PERCENT) {
   449→        offender->jailed = true;
   450→        LOG_WARN("DA_STRATEGY: Director jailed due to severe slash");
   451→    }
   452→
   453→    /* Persist director state */
   454→    state_enqueue_director_update(ctx->state,
   455→                                  offender->pubkey,
   456→                                  offender->stake,
   457→                                  offender->missed_blocks,
   458→                                  offender->jailed);
   459→}
   460→
   461→static void
   462→da_log_director_set(const da_epoch_t *epoch)
   463→{
   464→    LOG_INFO("DA_STRATEGY: Activated epoch %" PRIu64
   465→             " with %zu directors (Σ stake=%" PRIu64 ")",
   466→             epoch->epoch_index,
   467→             epoch->num_directors,
   468→             epoch->total_stake);
   469→
   470→#ifdef DEBUG
   471→    for (size_t i = 0; i < epoch->num_directors; ++i) {
   472→        char hex[ED25519_PUBKEY_LEN * 2 + 1];
   473→        bytes_to_hex(epoch->directors[i].pubkey,
   474→                     sizeof(epoch->directors[i].pubkey),
   475→                     hex,
   476→                     sizeof(hex));
   477→        LOG_DEBUG("DA_STRATEGY: Director[%zu]: pk=%s stake=%" PRIu64,
   478→                  i, hex, epoch->directors[i].stake);
   479→    }
   480→#endif
   481→}
   482→
   483→static int
   484→da_compare_director(const void *a, const void *b)
   485→{
   486→    const da_director_t *da = a;
   487→    const da_director_t *db = b;
   488→
   489→    /* Descending by stake, tiebreaker: pubkey lexicographically */
   490→    if (da->stake > db->stake) return -1;
   491→    if (da->stake < db->stake) return  1;
   492→    return memcmp(da->pubkey, db->pubkey, sizeof(da->pubkey));
   493→}
   494→
   495→/* ------------------------------------------------------------------------- *
   496→ * Strategy Interface V-Table
   497→ * ------------------------------------------------------------------------- */
   498→
   499→static const consensus_strategy_vtbl_t da_vtbl = {
   500→    .init           = da_init,
   501→    .free           = da_free,
   502→    .validate_block = da_validate_block,
   503→    .apply_block    = da_apply_block,
   504→    .name           = "Delegated-Artistry"
   505→};
   506→
   507→/*
   508→ * Public factory exported by da_strategy.h
   509→ */
   510→consensus_strategy_t *
   511→da_strategy_create(void)
   512→{
   513→    consensus_strategy_t *s = calloc(1, sizeof(*s));
   514→    if (!s) {
   515→        LOG_SYSERROR(errno, "DA_STRATEGY: Allocation failure");
   516→        return NULL;
   517→    }
   518→    s->vtbl      = &da_vtbl;
   519→    s->impl_ctx  = NULL;
   520→    return s;
   521→}

