1→/*
     2→ * HoloCanvas – Ledger Core
     3→ * File: block_builder.c
     4→ *
     5→ * Description:
     6→ *   The Block-Builder is responsible for assembling pending transactions into
     7→ *   candidate blocks and submitting them to the consensus engine for final
     8→ *   verification and commitment.  The module operates in its own worker thread,
     9→ *   watching the mem-pool for new transactions or a timeout, whichever comes
    10→ *   first.  Once triggered, it takes a consistent snapshot of the mem-pool,
    11→ *   builds a Merkle tree, computes the block header and forwards the block to
    12→ *   the Consensus service via gRPC.
    13→ *
    14→ *   The implementation favours robustness: it features extensive error
    15→ *   checking, clear separation between public and private API, and graceful
    16→ *   shutdown semantics.  All heap allocations are guarded, and the worker
    17→ *   thread is cancel-safe.
    18→ *
    19→ * Copyright (c) 2024, HoloCanvas Contributors
    20→ * SPDX-License-Identifier: MIT
    21→ */
    22→
    23→#include <errno.h>
    24→#include <inttypes.h>
    25→#include <pthread.h>
    26→#include <signal.h>
    27→#include <stdatomic.h>
    28→#include <stddef.h>
    29→#include <stdint.h>
    30→#include <stdio.h>
    31→#include <stdlib.h>
    32→#include <string.h>
    33→#include <time.h>
    34→#include <unistd.h>
    35→
    36→#include "block_builder.h"            /* Public interface for this module   */
    37→#include "config/ledger_config.h"     /* Constants, CLI / file overrides    */
    38→#include "consensus/consensus.h"      /* consensus_submit_block()           */
    39→#include "crypto/crypto.h"            /* sha256(), blake2b(), etc.          */
    40→#include "mem_pool/tx_pool.h"         /* tx_pool_*() API                    */
    41→#include "utils/logger.h"             /* log_debug(), log_error(), ...      */
    42→
    43→/* ------------------------------------------------------------------------- *
    44→ * Static helpers forward declarations                                       *
    45→ * ------------------------------------------------------------------------- */
    46→static void *           builder_thread_main(void *arg);
    47→static ledger_err_t     build_block(struct block_builder *ctx,
    48→                                    struct ledger_block *out_block);
    49→static ledger_err_t     compute_merkle_root(const tx_list_t *txs,
    50→                                            hash256_t        out_root);
    51→static inline uint64_t  unix_epoch_ms(void);
    52→
    53→/* ------------------------------------------------------------------------- *
    54→ * Public API                                                                *
    55→ * ------------------------------------------------------------------------- */
    56→
    57→ledger_err_t
    58→block_builder_init(struct block_builder        *builder,
    59→                   const struct builder_cfg    *cfg,
    60→                   struct tx_pool              *pool,
    61→                   consensus_client_t          *consensus)
    62→{
    63→    if (!builder || !cfg || !pool || !consensus) {
    64→        return LEDGER_EINVAL;
    65→    }
    66→
    67→    memset(builder, 0, sizeof *builder);
    68→    builder->cfg       = *cfg; /* structure copy */
    69→    builder->pool      = pool;
    70→    builder->consensus = consensus;
    71→    atomic_init(&builder->running, false);
    72→
    73→    int rc = pthread_mutex_init(&builder->lock, NULL);
    74→    if (rc != 0) {
    75→        return LEDGER_EOS; /* Out of system resources (POSIX mutex) */
    76→    }
    77→
    78→    rc = pthread_cond_init(&builder->cond, NULL);
    79→    if (rc != 0) {
    80→        pthread_mutex_destroy(&builder->lock);
    81→        return LEDGER_EOS;
    82→    }
    83→
    84→    return LEDGER_OK;
    85→}
    86→
    87→ledger_err_t
    88→block_builder_start(struct block_builder *builder)
    89→{
    90→    if (!builder) return LEDGER_EINVAL;
    91→
    92→    bool expected = false;
    93→    if (!atomic_compare_exchange_strong(&builder->running, &expected, true)) {
    94→        /* already running */
    95→        return LEDGER_EALREADY;
    96→    }
    97→
    98→    int rc = pthread_create(&builder->worker, NULL, builder_thread_main, builder);
    99→    if (rc != 0) {
   100→        atomic_store(&builder->running, false);
   101→        log_error("Block-Builder: failed to spawn worker thread: %s", strerror(rc));
   102→        return LEDGER_EOS;
   103→    }
   104→
   105→    pthread_detach(builder->worker);
   106→    return LEDGER_OK;
   107→}
   108→
   109→ledger_err_t
   110→block_builder_stop(struct block_builder *builder)
   111→{
   112→    if (!builder) return LEDGER_EINVAL;
   113→
   114→    bool expected = true;
   115→    if (!atomic_compare_exchange_strong(&builder->running, &expected, false)) {
   116→        return LEDGER_EALREADY; /* not running */
   117→    }
   118→
   119→    /* Wake the worker in case it's sleeping */
   120→    pthread_mutex_lock(&builder->lock);
   121→    pthread_cond_broadcast(&builder->cond);
   122→    pthread_mutex_unlock(&builder->lock);
   123→
   124→    /* Worker thread is detached; best effort join semantics via poll */
   125→    const uint64_t deadline = unix_epoch_ms() + 5000;
   126→    while (unix_epoch_ms() < deadline) {
   127→        if (atomic_load(&builder->terminated)) {
   128→            break;
   129→        }
   130→        usleep(20000); /* 20 ms */
   131→    }
   132→
   133→    if (!atomic_load(&builder->terminated)) {
   134→        log_error("Block-Builder: timed out waiting for stop");
   135→        return LEDGER_ETIMEDOUT;
   136→    }
   137→
   138→    pthread_cond_destroy(&builder->cond);
   139→    pthread_mutex_destroy(&builder->lock);
   140→    return LEDGER_OK;
   141→}
   142→
   143→/* ------------------------------------------------------------------------- *
   144→ * Worker thread                                                             *
   145→ * ------------------------------------------------------------------------- */
   146→
   147→static void *
   148→builder_thread_main(void *arg)
   149→{
   150→    struct block_builder *ctx = arg;
   151→    log_info("Block-Builder: worker thread started");
   152→
   153→    int rc = pthread_setcancelstate(PTHREAD_CANCEL_ENABLE, NULL);
   154→    if (rc == 0) {
   155→        pthread_setcanceltype(PTHREAD_CANCEL_DEFERRED, NULL);
   156→    }
   157→
   158→    uint64_t last_build_ms = unix_epoch_ms();
   159→
   160→    while (atomic_load(&ctx->running)) {
   161→
   162→        /* Determine whether we should create a block */
   163→        bool should_build = false;
   164→
   165→        /* 1) Transaction count triggers */
   166→        size_t tx_count = tx_pool_size(ctx->pool);
   167→        if (tx_count >= ctx->cfg.max_txs_per_block &&
   168→            ctx->cfg.max_txs_per_block != 0) {
   169→            should_build = true;
   170→        }
   171→
   172→        /* 2) Time-based trigger */
   173→        const uint64_t now_ms        = unix_epoch_ms();
   174→        const uint64_t elapsed_ms    = now_ms - last_build_ms;
   175→        if (!should_build &&
   176→            ctx->cfg.max_block_interval_ms > 0 &&
   177→            elapsed_ms >= ctx->cfg.max_block_interval_ms) {
   178→            should_build = true;
   179→        }
   180→
   181→        /* 3) Manual flush (via condition) */
   182→        pthread_mutex_lock(&ctx->lock);
   183→        if (!should_build) {
   184→            const struct timespec ts = {
   185→                .tv_sec  = (now_ms / 1000) + 1,
   186→                .tv_nsec = (now_ms % 1000) * 1e6,
   187→            };
   188→            pthread_cond_timedwait(&ctx->cond, &ctx->lock, &ts);
   189→        }
   190→        pthread_mutex_unlock(&ctx->lock);
   191→
   192→        if (!atomic_load(&ctx->running)) break;
   193→
   194→        if (!should_build) continue;
   195→
   196→        struct ledger_block block;
   197→        ledger_err_t       err = build_block(ctx, &block);
   198→        if (err != LEDGER_OK) {
   199→            log_error("Block-Builder: failed to build block: %s",
   200→                      ledger_err_to_string(err));
   201→            continue;
   202→        }
   203→
   204→        err = consensus_submit_block(ctx->consensus, &block);
   205→        if (err != LEDGER_OK) {
   206→            log_error("Block-Builder: consensus rejected block: %s",
   207→                      ledger_err_to_string(err));
   208→            /* Implement your own policy here (retry, stash, ...). */
   209→        } else {
   210→            last_build_ms = now_ms;
   211→            log_info("Block-Builder: successfully proposed block %" PRIu64,
   212→                     block.header.height);
   213→        }
   214→
   215→        ledger_block_free(&block); /* Free heap allocations in block */
   216→    }
   217→
   218→    log_info("Block-Builder: worker thread terminating");
   219→    atomic_store(&ctx->terminated, true);
   220→    pthread_exit(NULL);
   221→    return NULL;
   222→}
   223→
   224→/* ------------------------------------------------------------------------- *
   225→ * Block assembly                                                            *
   226→ * ------------------------------------------------------------------------- */
   227→
   228→/* build_block()
   229→ * Take a snapshot of tx-pool and compose a ledger_block ready for consensus.
   230→ */
   231→static ledger_err_t
   232→build_block(struct block_builder *ctx, struct ledger_block *out_block)
   233→{
   234→    if (!ctx || !out_block) return LEDGER_EINVAL;
   235→
   236→    size_t snapshot_size = ctx->cfg.max_txs_per_block
   237→                               ? ctx->cfg.max_txs_per_block
   238→                               : TX_POOL_MAX_POP_BULK;
   239→
   240→    tx_list_t *txs = tx_pool_pop_bulk(ctx->pool, snapshot_size);
   241→    if (!txs) {
   242→        return LEDGER_EEMPTY; /* No pending transactions */
   243→    }
   244→
   245→    memset(out_block, 0, sizeof *out_block);
   246→
   247→    /* Fill block header */
   248→    out_block->header.version        = LEDGER_BLOCK_VERSION;
   249→    out_block->header.timestamp_ms   = unix_epoch_ms();
   250→    out_block->header.height         = consensus_next_height(ctx->consensus);
   251→    out_block->header.prev_blockhash = consensus_last_hash(ctx->consensus);
   252→
   253→    /* Merkle root */
   254→    ledger_err_t err = compute_merkle_root(txs, out_block->header.merkle_root);
   255→    if (err != LEDGER_OK) {
   256→        tx_list_free(txs);
   257→        return err;
   258→    }
   259→
   260→    /* Copy txs to block body */
   261→    out_block->txs      = txs;
   262→    out_block->tx_count = txs->count;
   263→
   264→    /* Finalise block hash */
   265→    crypto_hash256_ctx hctx;
   266→    crypto_hash256_init(&hctx);
   267→    crypto_hash256_update(&hctx, &out_block->header, sizeof out_block->header);
   268→    crypto_hash256_update(&hctx, out_block->header.merkle_root,
   269→                          sizeof out_block->header.merkle_root);
   270→    crypto_hash256_final(&hctx, out_block->block_hash);
   271→
   272→    return LEDGER_OK;
   273→}
   274→
   275→/* ------------------------------------------------------------------------- *
   276→ * Merkle tree                                                               *
   277→ * ------------------------------------------------------------------------- */
   278→
   279→static ledger_err_t
   280→compute_merkle_root(const tx_list_t *txs, hash256_t out_root)
   281→{
   282→    if (!txs || txs->count == 0) {
   283→        return LEDGER_EINVAL;
   284→    }
   285→
   286→    size_t leaf_count = txs->count;
   287→    size_t level_count = leaf_count;
   288→
   289→    /* Allocate working buffer – power of two rounding */
   290→    size_t capacity = 1;
   291→    while (capacity < leaf_count) capacity <<= 1;
   292→    hash256_t *buf = calloc(capacity, sizeof(hash256_t));
   293→    if (!buf) return LEDGER_ENOMEM;
   294→
   295→    /* Copy leaves (tx hashes) */
   296→    for (size_t i = 0; i < leaf_count; ++i) {
   297→        memcpy(buf[i], txs->items[i]->tx_hash, sizeof(hash256_t));
   298→    }
   299→    /* Pad duplicate of last leaf if odd count */
   300→    for (size_t i = leaf_count; i < capacity; ++i) {
   301→        memcpy(buf[i], buf[leaf_count - 1], sizeof(hash256_t));
   302→    }
   303→
   304→    /* Iteratively hash pairs */
   305→    hash256_t tmp;
   306→    while (level_count > 1) {
   307→        size_t next_level = (level_count + 1) / 2;
   308→        for (size_t i = 0, j = 0; i < level_count; i += 2, ++j) {
   309→            crypto_hash256_ctx hctx;
   310→            crypto_hash256_init(&hctx);
   311→            crypto_hash256_update(&hctx, buf[i],   sizeof(hash256_t));
   312→            crypto_hash256_update(&hctx, buf[i+1], sizeof(hash256_t));
   313→            crypto_hash256_final(&hctx, tmp);
   314→            memcpy(buf[j], tmp, sizeof(hash256_t));
   315→        }
   316→        level_count = next_level;
   317→    }
   318→
   319→    memcpy(out_root, buf[0], sizeof(hash256_t));
   320→    free(buf);
   321→    return LEDGER_OK;
   322→}
   323→
   324→/* ------------------------------------------------------------------------- *
   325→ * Utilities                                                                 *
   326→ * ------------------------------------------------------------------------- */
   327→
   328→static inline uint64_t
   329→unix_epoch_ms(void)
   330→{
   331→    struct timespec ts;
   332→    clock_gettime(CLOCK_REALTIME, &ts);
   333→    return (uint64_t)ts.tv_sec * 1000ULL + (uint64_t)(ts.tv_nsec / 1e6);
   334→}

