   140→consensus_manager_t *consensus_manager_create(const char    *engine_so_path,
   141→                                              const char    *engine_cfg_json,
   142→                                              ledger_storage_t *store,
   143→                                              event_bus_t      *bus)
   144→{
   145→    if (!engine_so_path || !store || !bus) {
   146→        logger_log(LOG_LEVEL_ERR,
   147→                   "[ConsensusMgr] Invalid argument(s) to create()");
   148→        return NULL;
   149→    }
   150→
   151→    consensus_manager_t *mgr = calloc(1, sizeof(*mgr));
   152→    if (!mgr) {
   153→        logger_log(LOG_LEVEL_ERR,
   154→                   "[ConsensusMgr] Out of memory");
   155→        return NULL;
   156→    }
   157→
   158→    mgr->storage   = store;
   159→    mgr->event_bus = bus;
   160→
   161→    pthread_mutex_init(&mgr->q_mutex, NULL);
   162→    pthread_cond_init(&mgr->q_cond,  NULL);
   163→
   164→    if (!_load_engine(mgr, engine_so_path)) {
   165→        goto fail;
   166→    }
   167→
   168→    /* Initialise engine with config JSON */
   169→    if (!mgr->engine.init(engine_cfg_json, store, bus)) {
   170→        logger_log(LOG_LEVEL_ERR,
   171→                   "[ConsensusMgr] Engine(%s) failed to init",
   172→                   mgr->engine.name);
   173→        goto fail;
   174→    }
   175→
   176→    /* Spawn worker thread */
   177→    if (pthread_create(&mgr->worker, NULL,
   178→                       _worker_loop, mgr) != 0) {
   179→        logger_log(LOG_LEVEL_ERR,
   180→                   "[ConsensusMgr] Failed to spawn worker thread: %s",
   181→                   strerror(errno));
   182→        goto fail;
   183→    }
   184→
   185→    logger_log(LOG_LEVEL_INFO,
   186→               "[ConsensusMgr] Started with engine: %s",
   187→               mgr->engine.name);
   188→    return mgr;
   189→
   190→fail:
   191→    _unload_engine(mgr);
   192→    pthread_mutex_destroy(&mgr->q_mutex);
   193→    pthread_cond_destroy(&mgr->q_cond);
   194→    free(mgr);
   195→    return NULL;
   196→}
