   253→static void _enqueue_block(consensus_manager_t *mgr, block_t *blk)
   254→{
   255→    struct blk_node *node = calloc(1, sizeof(*node));
   256→    if (!node) {
   257→        logger_log(LOG_LEVEL_ERR,
   258→                   "[ConsensusMgr] OOM while enqueueing block");
   259→        return;
   260→    }
   261→    node->blk = blk;
   262→
   263→    pthread_mutex_lock(&mgr->q_mutex);
   264→    if (mgr->q_tail) {
   265→        mgr->q_tail->next = node;
   266→        mgr->q_tail       = node;
   267→    } else {
   268→        mgr->q_head = mgr->q_tail = node;
   269→    }
   270→    pthread_cond_signal(&mgr->q_cond);
   271→    pthread_mutex_unlock(&mgr->q_mutex);
   272→}
