   274→static block_t *_dequeue_block(consensus_manager_t *mgr)
   275→{
   276→    pthread_mutex_lock(&mgr->q_mutex);
   277→    while (!mgr->q_head && !mgr->stop_requested) {
   278→        pthread_cond_wait(&mgr->q_cond, &mgr->q_mutex);
   279→    }
   280→
   281→    if (mgr->stop_requested) {
   282→        pthread_mutex_unlock(&mgr->q_mutex);
   283→        return NULL;
   284→    }
   285→
   286→    struct blk_node *node = mgr->q_head;
   287→    mgr->q_head = node->next;
   288→    if (!mgr->q_head) mgr->q_tail = NULL;
   289→
   290→    pthread_mutex_unlock(&mgr->q_mutex);
   291→
   292→    block_t *blk = node->blk;
   293→    free(node);
   294→    return blk;
   295→}
