   323→            logger_log(LOG_LEVEL_ERR,
   324→                       "[ConsensusMgr] Block@%lu finalisation failed: %s",
   325→                       blk->height,
   326→                       err_msg ? err_msg : "(no details)");
   327→            free(err_msg);
   328→            free(blk);
   329→            continue; /* Inconsistent state, do not commit */
   330→        }
   331→
   332→        /* Step 3: Commit to durable storage */
   333→        if (!ledger_storage_put_block(mgr->storage, blk) ||
   334→            !ledger_storage_set_state_root(mgr->storage,
   335→                                           new_state_root)) {
   336→            logger_log(LOG_LEVEL_ERR,
   337→                       "[ConsensusMgr] Storage commit failed at height %lu",
   338→                       blk->height);
   339→            free(blk);
   340→            continue;
   341→        }
   342→
   343→        /* Step 4: Publish consensus event to bus */
   344→        event_bus_publish(mgr->event_bus,
