   346→                          blk, sizeof(*blk));
   347→
   348→        logger_log(LOG_LEVEL_INFO,
   349→                   "[ConsensusMgr] Block@%lu committed (root=%02x%02x…)",
   350→                   blk->height,
   351→                   new_state_root[0], new_state_root[1]);
   352→
   353→        free(blk);
   354→    }
   355→
   356→    return NULL;
   357→}
