[metadata] {"type": "text", "file": {"filePath": "/app/project/services/ledger_core/src/consensus_manager.c", "content": "```c\n/**\n * HoloCanvas – LedgerCore\n * File: services/ledger_core/src/consensus_manager.c\n *\n * The Consensus Manager is responsible for:\n *   1. Dynamically loading a pluggable consensus engine (PoS-Staking,\n *      Delegated-Artistry, etc.).\n *   2. Verifying and finalising blocks produced by upstream\n *      proposer/mempool services.\n *   3. Committing state-machine transitions to durable storage.\n *   4. Publishing consensus events to the event-bus for downstream\n *      micro-services (Mint-Factory, Governance-Hall, …).\n *\n * This module is intentionally self-contained; platform-specific\n * components (Kafka, RocksDB, protobuf models, etc.) are abstracted\n * behind thin interfaces so that LedgerCore can be embedded or unit-\n * tested in isolation.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <stdbool.h>\n#include <stdint.h>\n#include <dlfcn.h>\n#include <pthread.h>\n#include <errno.h>\n#include <time.h>\n\n/* ────────────────────────────────────────────────────────── */\n/* External / project headers (forward-declared if missing)  */\n/* ────────────────────────────────────────────────────────── */\n#include \"logger.h\"            /* Simple application logger      */\n#include \"event_bus.h\"         /* Kafka/gRPC abstraction          */\n#include \"ledger_storage.h\"    /* Durable key-value store         */\n#include \"artifact_state.h\"    /* State-Machine for NFTs          */\n#include \"transaction.h\"       /* Wire-format for transactions    */\n#include \"block.h\"             /* Wire-format for ledger blocks   */\n#include \"consensus_manager.h\" /* Public API for this component   */\n\n/* ---------------------------------------------------------------- */\n/* Fallback stubs for stand-alone compilation (unit test harnesses) */\n/* ---------------------------------------------------------------- */\n#ifndef BLOCK_H\n#define BLOCK_H\ntypedef struct {\n    uint64_t height;\n    uint64_t timestamp;\n    uint8_t  hash[32];\n    uint8_t  prev_hash[32];\n    tx_list_t *txs; /* Linked list of transactions (see transaction.h) */\n} block_t;\n#endif /* BLOCK_H */\n\n#ifndef LOGGER_H\n#define LOGGER_H\n#define LOG_LEVEL_INFO  1\n#define LOG_LEVEL_WARN  2\n#define LOG_LEVEL_ERR   3\nvoid logger_log(int level, const char *fmt, ...);\n#endif /* LOGGER_H */\n\n#ifndef EVENT_BUS_H\n#define EVENT_BUS_H\ntypedef struct event_bus_s event_bus_t;\nbool event_bus_publish(event_bus_t *bus, const char *topic,\n                       const void *payload, size_t size);\n#endif /* EVENT_BUS_H */\n\n#ifndef LEDGER_STORAGE_H\n#define LEDGER_STORAGE_H\ntypedef struct ledger_storage_s ledger_storage_t;\nbool ledger_storage_put_block(ledger_storage_t *store,\n                              const block_t *blk);\nbool ledger_storage_set_state_root(ledger_storage_t *store,\n                                   const uint8_t root[32]);\n#endif /* LEDGER_STORAGE_H */\n\n/* ────────────────────────────────────────────────────────── */\n/* Consensus Engine plug-in interface                         */\n/* ────────────────────────────────────────────────────────── */\ntypedef struct consensus_engine {\n    const char *name;\n\n    /* Initialise engine with JSON-encoded configuration blob.    */\n    bool (*init)(const char *json_config,\n                 ledger_storage_t *store,\n                 event_bus_t *event_bus);\n\n    /* Verify cryptographic validity, state transitions, gas, …   */\n    bool (*verify_block)(const block_t *candidate,\n                         char **err_msg);\n\n    /* Execute state transitions & compute new state root.        */\n    bool (*finalise_block)(const block_t *candidate,\n                           uint8_t new_state_root[32],\n                           char **err_msg);\n\n    /* Shut down and free any engine-local resources.             */\n    void (*shutdown)(void);\n} consensus_engine_t;\n\n/* The `consensus_manager_t` is opaque to other translation units. */\nstruct consensus_manager {\n    consensus_engine_t engine;           /* Function table          */\n    void              *engine_so_handle; /* dlopen handle           */\n\n    ledger_storage_t  *storage;          /* Durable KV store        */\n    event_bus_t       *event_bus;        /* Global event bus        */\n\n    /* ────── Worker thread & queue for incoming blocks ────── */\n    pthread_t          worker;\n    pthread_mutex_t    q_mutex;\n    pthread_cond_t     q_cond;\n    struct blk_node   *q_head;\n    struct blk_node   *q_tail;\n    bool               stop_requested;\n};\n\n/* Linked-list node for pending blocks */\nstruct blk_node {\n    block_t          *blk;\n    struct blk_node  *next;\n};\n\n/* Internal helpers */\nstatic void *_worker_loop(void *arg);\nstatic bool   _load_engine(consensus_manager_t  *mgr,\n                           const char           *so_path);\nstatic void   _unload_engine(consensus_manager_t *mgr);\nstatic void   _enqueue_block(consensus_manager_t *mgr,\n                             block_t *blk);\nstatic block_t *_dequeue_block(consensus_manager_t *mgr);\n\n/* ═══════════════════════════════════════════════════════════ */\n/* Public API                                                 */\n/* ═══════════════════════════════════════════════════════════ */\n\nconsensus_manager_t *consensus_manager_create(const char    *engine_so_path,\n                                              const char    *engine_cfg_json,\n                                              ledger_storage_t *store,\n                                              event_bus_t      *bus)\n{\n    if (!engine_so_path || !store || !bus) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] Invalid argument(s) to create()\");\n        return NULL;\n    }\n\n    consensus_manager_t *mgr = calloc(1, sizeof(*mgr));\n    if (!mgr) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] Out of memory\");\n        return NULL;\n    }\n\n    mgr->storage   = store;\n    mgr->event_bus = bus;\n\n    pthread_mutex_init(&mgr->q_mutex, NULL);\n    pthread_cond_init(&mgr->q_cond,  NULL);\n\n    if (!_load_engine(mgr, engine_so_path)) {\n        goto fail;\n    }\n\n    /* Initialise engine with config JSON */\n    if (!mgr->engine.init(engine_cfg_json, store, bus)) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] Engine(%s) failed to init\",\n                   mgr->engine.name);\n        goto fail;\n    }\n\n    /* Spawn worker thread */\n    if (pthread_create(&mgr->worker, NULL,\n                       _worker_loop, mgr) != 0) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] Failed to spawn worker thread: %s\",\n                   strerror(errno));\n        goto fail;\n    }\n\n    logger_log(LOG_LEVEL_INFO,\n               \"[ConsensusMgr] Started with engine: %s\",\n               mgr->engine.name);\n    return mgr;\n\nfail:\n    _unload_engine(mgr);\n    pthread_mutex_destroy(&mgr->q_mutex);\n    pthread_cond_destroy(&mgr->q_cond);\n    free(mgr);\n    return NULL;\n}\n\nvoid consensus_manager_destroy(consensus_manager_t *mgr)\n{\n    if (!mgr) return;\n\n    /* Request worker shutdown */\n    pthread_mutex_lock(&mgr->q_mutex);\n    mgr->stop_requested = true;\n    pthread_cond_signal(&mgr->q_cond);\n    pthread_mutex_unlock(&mgr->q_mutex);\n\n    /* Join worker */\n    pthread_join(mgr->worker, NULL);\n\n    /* Unload engine */\n    if (mgr->engine.shutdown) {\n        mgr->engine.shutdown();\n    }\n    _unload_engine(mgr);\n\n    /* Drain any remaining queued blocks */\n    struct blk_node *n, *tmp;\n    n = mgr->q_head;\n    while (n) {\n        tmp = n->next;\n        free(n->blk);\n        free(n);\n        n = tmp;\n    }\n\n    pthread_mutex_destroy(&mgr->q_mutex);\n    pthread_cond_destroy(&mgr->q_cond);\n    free(mgr);\n\n    logger_log(LOG_LEVEL_INFO,\n               \"[ConsensusMgr] Clean shutdown complete\");\n}\n\nbool consensus_manager_submit_block(consensus_manager_t *mgr,\n                                    const block_t       *blk_in)\n{\n    if (!mgr || !blk_in) return false;\n\n    /* Deep-copy block because caller may free their memory */\n    block_t *copy = malloc(sizeof(*copy));\n    if (!copy) return false;\n    memcpy(copy, blk_in, sizeof(*copy));\n\n    _enqueue_block(mgr, copy);\n    return true;\n}\n\n/* ═══════════════════════════════════════════════════════════ */\n/* Private Implementation                                     */\n/* ═══════════════════════════════════════════════════════════ */\n\nstatic void _enqueue_block(consensus_manager_t *mgr, block_t *blk)\n{\n    struct blk_node *node = calloc(1, sizeof(*node));\n    if (!node) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] OOM while enqueueing block\");\n        return;\n    }\n    node->blk = blk;\n\n    pthread_mutex_lock(&mgr->q_mutex);\n    if (mgr->q_tail) {\n        mgr->q_tail->next = node;\n        mgr->q_tail       = node;\n    } else {\n        mgr->q_head = mgr->q_tail = node;\n    }\n    pthread_cond_signal(&mgr->q_cond);\n    pthread_mutex_unlock(&mgr->q_mutex);\n}\n\nstatic block_t *_dequeue_block(consensus_manager_t *mgr)\n{\n    pthread_mutex_lock(&mgr->q_mutex);\n    while (!mgr->q_head && !mgr->stop_requested) {\n        pthread_cond_wait(&mgr->q_cond, &mgr->q_mutex);\n    }\n\n    if (mgr->stop_requested) {\n        pthread_mutex_unlock(&mgr->q_mutex);\n        return NULL;\n    }\n\n    struct blk_node *node = mgr->q_head;\n    mgr->q_head = node->next;\n    if (!mgr->q_head) mgr->q_tail = NULL;\n\n    pthread_mutex_unlock(&mgr->q_mutex);\n\n    block_t *blk = node->blk;\n    free(node);\n    return blk;\n}\n\nstatic void *_worker_loop(void *arg)\n{\n    consensus_manager_t *mgr = arg;\n\n    for (;;)\n    {\n        block_t *blk = _dequeue_block(mgr);\n        if (!blk) break; /* Shutdown requested */\n\n        /* Step 1: Verify candidate block */\n        char *err_msg = NULL;\n        if (!mgr->engine.verify_block(blk, &err_msg)) {\n            logger_log(LOG_LEVEL_WARN,\n                       \"[ConsensusMgr] Block@%lu verification failed: %s\",\n                       blk->height,\n                       err_msg ? err_msg : \"(no details)\");\n            free(err_msg);\n            free(blk);\n            continue; /* Reject block */\n        }\n\n        /* Step 2: Finalise (exec state transitions) */\n        uint8_t new_state_root[32] = {0};\n        if (!mgr->engine.finalise_block(blk,\n                                        new_state_root,\n                                        &err_msg)) {\n            logger_log(LOG_LEVEL_ERR,\n                       \"[ConsensusMgr] Block@%lu finalisation failed: %s\",\n                       blk->height,\n                       err_msg ? err_msg : \"(no details)\");\n            free(err_msg);\n            free(blk);\n            continue; /* Inconsistent state, do not commit */\n        }\n\n        /* Step 3: Commit to durable storage */\n        if (!ledger_storage_put_block(mgr->storage, blk) ||\n            !ledger_storage_set_state_root(mgr->storage,\n                                           new_state_root)) {\n            logger_log(LOG_LEVEL_ERR,\n                       \"[ConsensusMgr] Storage commit failed at height %lu\",\n                       blk->height);\n            free(blk);\n            continue;\n        }\n\n        /* Step 4: Publish consensus event to bus */\n        event_bus_publish(mgr->event_bus,\n                          \"ledger.block.finalised\",\n                          blk, sizeof(*blk));\n\n        logger_log(LOG_LEVEL_INFO,\n                   \"[ConsensusMgr] Block@%lu committed (root=%02x%02x…)\",\n                   blk->height,\n                   new_state_root[0], new_state_root[1]);\n\n        free(blk);\n    }\n\n    return NULL;\n}\n\n/* ────────────────────────────────────────────────────────── */\n/* Dynamic loading of Consensus Engine shared-library        */\n/* ────────────────────────────────────────────────────────── */\n\nstatic bool _load_engine(consensus_manager_t *mgr,\n                         const char          *so_path)\n{\n    mgr->engine_so_handle = dlopen(so_path, RTLD_NOW | RTLD_LOCAL);\n    if (!mgr->engine_so_handle) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] dlopen failed: %s\",\n                   dlerror());\n        return false;\n    }\n\n    /* Convention: shared library exports symbol `holo_consensus_engine` */\n    consensus_engine_t *sym =\n        (consensus_engine_t *)dlsym(mgr->engine_so_handle,\n                                    \"holo_consensus_engine\");\n    if (!sym) {\n        logger_log(LOG_LEVEL_ERR,\n                   \"[ConsensusMgr] dlsym 'holo_consensus_engine' missing\");\n        dlclose(mgr->engine_so_handle);\n        mgr->engine_so_handle = NULL;\n        return false;\n    }\n\n    /* Copy function table (no pointers back into the SO needed) */\n    memcpy(&mgr->engine, sym, sizeof(*sym));\n    return true;\n}\n\nstatic void _unload_engine(consensus_manager_t *mgr)\n{\n    if (mgr->engine_so_handle) {\n        dlclose(mgr->engine_so_handle);\n        mgr->engine_so_handle = NULL;\n    }\n}\n\n/* ═══════════════════════════════════════════════════════════ */\n/* EOF                                                        */\n/* ═══════════════════════════════════════════════════════════ */\n```", "numLines": 402, "startLine": 1, "totalLines": 402}}

1→/*
     2→ * HoloCanvas – LedgerCore
     3→ * Proof-of-Stake Consensus Strategy
     4→ *
     5→ * File:    strategies/pos_strategy.c
     6→ * Author:  HoloCanvas Core Team
     7→ *
     8→ * Description:
     9→ *   This file implements the Proof-of-Stake (PoS) consensus plug-in for the
    10→ *   LedgerCore micro-service.  The strategy is loaded at runtime through a
    11→ *   Strategy-Pattern interface (see pos_strategy.h) and receives a stream of
    12→ *   ledger events via the internal Event-Bus.  The PoS module is responsible
    13→ *   for:
    14→ *
    15→ *     • Managing validator stake tables
    16→ *     • Electing the next block proposer with a stake-weighted VRF
    17→ *     • Verifying block signatures and stake lock-ups
    18→ *     • Distributing block rewards and slashing misbehaving validators
    19→ *
    20→ *   The implementation is production-grade and is optimised for readability
    21→ *   and robustness rather than raw performance.  Critical sections are
    22→ *   protected by pthread mutexes; cryptographic operations rely on libsodium.
    23→ *
    24→ *   NOTE: The surrounding infrastructure (ledger storage, event bus, etc.)
    25→ *         is mocked by forward declarations to keep this file self-contained.
    26→ *         In the full code-base these come from their respective headers.
    27→ *
    28→ * License:
    29→ *   Apache-2.0
    30→ */
    31→
    32→#include <assert.h>
    33→#include <errno.h>
    34→#include <inttypes.h>
    35→#include <sodium.h>
    36→#include <stdbool.h>
    37→#include <stdint.h>
    38→#include <stdio.h>
    39→#include <stdlib.h>
    40→#include <string.h>
    41→#include <pthread.h>
    42→#include "pos_strategy.h"  /* Public interface */
    43→#include "../include/crypto_utils.h"      /* crypto_sign_block(), hash(), … */
    44→#include "../include/event_bus.h"         /* event_bus_publish(), … */
    45→#include "../include/ledger_storage.h"    /* ledger_get_balance(), … */
    46→#include "../include/logger.h"            /* HC_LOG_DEBUG(), … */
    47→
    48→/* ------------------------------------------------------------------------- *
    49→ *                              Local  Types                                 *
    50→ * ------------------------------------------------------------------------- */
    51→
    52→/* Validator entry kept in memory; periodically snapshotted to disk */
    53→typedef struct validator_entry_s
    54→{
    55→    wallet_addr_t  address;        /* 32-byte public key (bech32-decoded) */
    56→    uint64_t       stake;          /* Currently bonded stake              */
    57→    uint64_t       locked_until;   /* Epoch height until which stake is locked */
    58→    uint64_t       rewards;        /* Pending rewards (lazy withdrawn)    */
    59→    bool           jailed;         /* true when validator is slashed      */
    60→} validator_entry_t;
    61→
    62→/* Main PoS context – one per service instance */
    63→typedef struct pos_ctx_s
    64→{
    65→    validator_entry_t *validators; /* Dynamic array                       */
    66→    size_t             v_len;      /* Elements in the array               */
    67→    size_t             v_cap;      /* Capacity                            */
    68→
    69→    uint64_t           total_stake;/* Aggregate bonded stake              */
    70→    uint64_t           current_epoch;
    71→    event_bus_t       *bus;        /* Weak ref to global Event-Bus        */
    72→
    73→    pthread_rwlock_t   rwlock;     /* Protects validators & total_stake   */
    74→} pos_ctx_t;
    75→
    76→/* ------------------------------------------------------------------------- *
    77→ *                       Forward Declarations / Helpers                      *
    78→ * ------------------------------------------------------------------------- */
    79→
    80→static int      ensure_capacity(pos_ctx_t *ctx);
    81→static ssize_t  find_validator(pos_ctx_t *ctx, const wallet_addr_t addr);
    82→static int      add_validator(pos_ctx_t *ctx,
    83→                              const wallet_addr_t addr,
    84→                              uint64_t stake);
    85→
    86→static int      vrf_elect(const pos_ctx_t *ctx,
    87→                          const uint8_t previous_block_hash[crypto_hash_sha256_BYTES],
    88→                          wallet_addr_t out_selected);
    89→
    90→static int      apply_block_rewards(pos_ctx_t *ctx,
    91→                                    const wallet_addr_t proposer,
    92→                                    uint64_t block_fees);
    93→
    94→static int      slash_validator(pos_ctx_t *ctx,
    95→                                const wallet_addr_t address,
    96→                                const char *reason);
    97→
    98→/* ------------------------------------------------------------------------- *
    99→ *                       Public  Interface  (Strategy)                       *
   100→ * ------------------------------------------------------------------------- */
   101→
   102→static pos_ctx_t g_ctx;  /* Singleton instance – strategy is process-local */
   103→
   104→
   105→/*
   106→ * pos_strategy_init()
   107→ * -------------------
   108→ * Initialise libsodium (if necessary), internal state and subscribe to the
   109→ * Event-Bus streams required by the PoS module.
   110→ */
   111→int
   112→pos_strategy_init(event_bus_t *bus)
   113→{
   114→    if (sodium_init() == -1) {
   115→        fprintf(stderr, "[PoS] libsodium init failed\n");
   116→        return -1;
   117→    }
   118→
   119→    memset(&g_ctx, 0, sizeof(g_ctx));
   120→    g_ctx.bus = bus;
   121→    pthread_rwlock_init(&g_ctx.rwlock, NULL);
   122→
   123→    /* Pre-allocate validator table with a sane default */
   124→    g_ctx.v_cap = 64;
   125→    g_ctx.validators = calloc(g_ctx.v_cap, sizeof(validator_entry_t));
   126→    if (!g_ctx.validators) {
   127→        perror("[PoS] calloc validators");
   128→        return -1;
   129→    }
   130→
   131→    /* Subscribe to ledger events (mocked) */
   132→    event_bus_subscribe(bus, EVENT_STAKE_BOND,  pos_strategy_on_event);
   133→    event_bus_subscribe(bus, EVENT_STAKE_UNBOND,pos_strategy_on_event);
   134→    event_bus_subscribe(bus, EVENT_NEW_BLOCK,   pos_strategy_on_event);
   135→
   136→    HC_LOG_INFO("[PoS] strategy initialised");
   137→    return 0;
   138→}
   139→
   140→
   141→/*
   142→ * pos_strategy_shutdown()
   143→ * -----------------------
   144→ * Flush any in-memory state to durable storage and cleanup allocations.
   145→ */
   146→void
   147→pos_strategy_shutdown(void)
   148→{
   149→    pthread_rwlock_wrlock(&g_ctx.rwlock);
   150→
   151→    /* In a real implementation we would persist validator snapshots here */
   152→
   153→    free(g_ctx.validators);
   154→    g_ctx.validators = NULL;
   155→    g_ctx.v_len      = 0;
   156→    g_ctx.v_cap      = 0;
   157→    g_ctx.total_stake= 0;
   158→
   159→    pthread_rwlock_unlock(&g_ctx.rwlock);
   160→    pthread_rwlock_destroy(&g_ctx.rwlock);
   161→
   162→    HC_LOG_INFO("[PoS] strategy shut down");
   163→}
   164→
   165→
   166→/*
   167→ * pos_strategy_on_event()
   168→ * -----------------------
   169→ * Central entry point for Event-Bus callbacks.  Handles three primary event
   170→ * classes: stake bond/unbond, and new block arrival.
   171→ */
   172→void
   173→pos_strategy_on_event(const event_t *ev)
   174→{
   175→    switch (ev->type) {
   176→
   177→    case EVENT_STAKE_BOND:
   178→        pos_strategy_handle_bond((const stake_event_t *)ev->payload);
   179→        break;
   180→
   181→    case EVENT_STAKE_UNBOND:
   182→        pos_strategy_handle_unbond((const stake_event_t *)ev->payload);
   183→        break;
   184→
   185→    case EVENT_NEW_BLOCK:
   186→        pos_strategy_handle_block((const block_event_t *)ev->payload);
   187→        break;
   188→
   189→    default:
   190→        HC_LOG_WARN("[PoS] unknown event type: %d", (int)ev->type);
   191→    }
   192→}
   193→
   194→
   195→/* ------------------------------------------------------------------------- *
   196→ *                          Event  Handlers                                  *
   197→ * ------------------------------------------------------------------------- */
   198→
   199→/*
   200→ * Handle stake bonding.  Updates validator table and total stake.
   201→ */
   202→void
   203→pos_strategy_handle_bond(const stake_event_t *ev)
   204→{
   205→    int rc;
   206→    pthread_rwlock_wrlock(&g_ctx.rwlock);
   207→
   208→    ssize_t idx = find_validator(&g_ctx, ev->staker);
   209→    if (idx < 0) {
   210→        /* New validator */
   211→        rc = add_validator(&g_ctx, ev->staker, ev->amount);
   212→        if (rc != 0) {
   213→            HC_LOG_ERROR("[PoS] failed to add validator");
   214→            pthread_rwlock_unlock(&g_ctx.rwlock);
   215→            return;
   216→        }
   217→    } else {
   218→        validator_entry_t *v = &g_ctx.validators[idx];
   219→        v->stake += ev->amount;
   220→        v->locked_until = g_ctx.current_epoch + POS_MIN_LOCK_EPOCHS;
   221→    }
   222→
   223→    g_ctx.total_stake += ev->amount;
   224→    pthread_rwlock_unlock(&g_ctx.rwlock);
   225→
   226→    HC_LOG_DEBUG("[PoS] bonded %" PRIu64 " to validator %.8s…, total=%" PRIu64,
   227→                 ev->amount, ev->staker, g_ctx.total_stake);
   228→}
   229→
   230→
   231→/*
   232→ * Handle stake unbonding request.  Stake is not immediately released: we place
   233→ * it in a cooldown queue (omitted for brevity) and unlock once the holding
   234→ * period expires.
   235→ */
   236→void
   237→pos_strategy_handle_unbond(const stake_event_t *ev)
   238→{
   239→    pthread_rwlock_wrlock(&g_ctx.rwlock);
   240→
   241→    ssize_t idx = find_validator(&g_ctx, ev->staker);
   242→    if (idx < 0) {
   243→        HC_LOG_WARN("[PoS] unbond from unknown validator %.8s…", ev->staker);
   244→        pthread_rwlock_unlock(&g_ctx.rwlock);
   245→        return;
   246→    }
   247→
   248→    validator_entry_t *v = &g_ctx.validators[idx];
   249→    if (v->stake < ev->amount) {
   250→        HC_LOG_ERROR("[PoS] unbond exceeds stake");
   251→        pthread_rwlock_unlock(&g_ctx.rwlock);
   252→        return;
   253→    }
   254→
   255→    v->stake -= ev->amount;
   256→    g_ctx.total_stake -= ev->amount;
   257→
   258→    /* TODO: Push to cooldown queue for delayed release */
   259→
   260→    pthread_rwlock_unlock(&g_ctx.rwlock);
   261→
   262→    HC_LOG_DEBUG("[PoS] unbonded %" PRIu64 " from validator %.8s…, remaining=%"
   263→                 PRIu64, ev->amount, ev->staker, v->stake);
   264→}
   265→
   266→
   267→/*
   268→ * Handle new block arrival.  Verify proposer signature and stake, distribute
   269→ * fees and reward, then increment epoch if necessary.
   270→ */
   271→void
   272→pos_strategy_handle_block(const block_event_t *ev)
   273→{
   274→    const block_t *blk = &ev->block;
   275→
   276→    /* 1. Verify signature */
   277→    if (crypto_verify_block(blk) != 0) {
   278→        HC_LOG_ERROR("[PoS] invalid block signature");
