   381→static ssize_t
   382→find_validator(pos_ctx_t *ctx, const wallet_addr_t addr)
   383→{
   384→    for (size_t i = 0; i < ctx->v_len; ++i) {
   385→        if (memcmp(ctx->validators[i].address, addr, WALLET_ADDR_LEN) == 0)
   386→            return (ssize_t)i;
