   397→static int
   398→add_validator(pos_ctx_t *ctx,
   399→              const wallet_addr_t addr,
   400→              uint64_t stake)
   401→{
   402→    if (ensure_capacity(ctx) != 0)
   403→        return -1;
   404→
   405→    validator_entry_t *v = &ctx->validators[ctx->v_len++];
   406→    memset(v, 0, sizeof(*v));
