   418→/*
   419→ * vrf_elect()
   420→ * -----------
   421→ * Perform stake-weighted random election using libsodium's crypto_core_ed25519.
   422→ * The VRF simulates a beacon: H = Hash(prev_hash || validator_pub || epoch).
   423→ * Each validator computes H and compares it with a threshold derived from
   424→ * stake/total.  The smallest valid H wins.  For centralised selection (this
   425→ * service) we compute H for all candidates.
   426→ */
   427→static int
   428→vrf_elect(const pos_ctx_t *ctx,
   429→          const uint8_t prev_block_hash[crypto_hash_sha256_BYTES],
   430→          wallet_addr_t out_selected)
   431→{
   432→    uint8_t min_hash[crypto_hash_sha256_BYTES];
   433→    bool    selected = false;
   434→
   435→    for (size_t i = 0; i < ctx->v_len; ++i) {
   436→        const validator_entry_t *v = &ctx->validators[i];
   437→        if (v->jailed || v->stake == 0)
   438→            continue;
   439→
   440→        /* Beacon: hash(prev_hash | validator_pub | epoch_le) */
   441→        uint8_t buf[crypto_hash_sha256_BYTES + WALLET_ADDR_LEN + sizeof(uint64_t)];
   442→        size_t  off = 0;
   443→        memcpy(buf + off, prev_block_hash, crypto_hash_sha256_BYTES); off += crypto_hash_sha256_BYTES;
   444→        memcpy(buf + off, v->address, WALLET_ADDR_LEN);               off += WALLET_ADDR_LEN;
   445→        uint64_t epoch_le = htole64(ctx->current_epoch);
   446→        memcpy(buf + off, &epoch_le, sizeof(epoch_le));
   447→
   448→        uint8_t h[crypto_hash_sha256_BYTES];
   449→        crypto_hash_sha256(h, buf, sizeof(buf));
   450→
   451→        /* Convert leading 16 bytes to a 128-bit integer for comparison */
   452→        if (!selected || memcmp(h, min_hash, 16) < 0) {
   453→            memcpy(min_hash, h, sizeof(min_hash));
   454→            memcpy(out_selected, v->address, WALLET_ADDR_LEN);
   455→            selected = true;
   456→        }
   457→    }
   458→
   459→    if (!selected)
   460→        return -1;
   461→
   462→    return 0;
   463→}
   464→
   465→
   466→/*
   467→ * apply_block_rewards()
   468→ * ---------------------
   469→ * Credit proposer with block reward plus fees, and distribute a portion to
   470→ * delegators (omitted for brevity).
   471→ */
   472→static int
   473→apply_block_rewards(pos_ctx_t *ctx,
   474→                    const wallet_addr_t proposer,
   475→                    uint64_t block_fees)
   476→{
   477→    static const uint64_t BASE_REWARD = 5 * HC_COINS; /* 5 tokens per block */
   478→
   479→    pthread_rwlock_wrlock(&ctx->rwlock);
   480→    ssize_t idx = find_validator(ctx, proposer);
