   486→    validator_entry_t *v = &ctx->validators[idx];
   487→    v->rewards += BASE_REWARD + block_fees;
   488→    pthread_rwlock_unlock(&ctx->rwlock);
   489→
   490→    /* Emit reward event */
   491→    reward_event_t rev = {
   492→        .validator = {0},
   493→        .amount    = BASE_REWARD + block_fees
   494→    };
   495→    memcpy(rev.validator, proposer, WALLET_ADDR_LEN);
   496→    event_t ev = {
   497→        .type    = EVENT_REWARD,
   498→        .payload = &rev
   499→    };
   500→    event_bus_publish(ctx->bus, &ev);
   501→
   502→    HC_LOG_DEBUG("[PoS] rewarded %.8s… with %" PRIu64,
   503→                 proposer, rev.amount);
   504→    return 0;
   505→}
