   507→
   508→/*
   509→ * slash_validator()
   510→ * -----------------
   511→ * Slash a validator for misbehaviour by burning a percentage of its stake and
   512→ * jailing it for several epochs.
   513→ */
   514→static int
   515→slash_validator(pos_ctx_t *ctx,
   516→                const wallet_addr_t address,
   517→                const char *reason)
   518→{
   519→    pthread_rwlock_wrlock(&ctx->rwlock);
   520→    ssize_t idx = find_validator(ctx, address);
   521→    if (idx < 0) {
   522→        pthread_rwlock_unlock(&ctx->rwlock);
   523→        return -1;
   524→    }
   525→
   526→    validator_entry_t *v = &ctx->validators[idx];
   527→    uint64_t penalty = v->stake / POS_SLASH_FRACTION;
   528→    v->stake -= penalty;
   529→    v->jailed = true;
   530→
   531→    ctx->total_stake -= penalty;
   532→    pthread_rwlock_unlock(&ctx->rwlock);
   533→
   534→    HC_LOG_WARN("[PoS] validator %.8s… slashed by %" PRIu64 " (%s)",
   535→                address, penalty, reason);
   536→
   537→    /* Emit slashing event */
   538→    slash_event_t sev = {
   539→        .validator = {0},
   540→        .amount    = penalty,
   541→        .reason    = {0}
   542→    };
   543→    memcpy(sev.validator, address, WALLET_ADDR_LEN);
   544→    strncpy(sev.reason, reason, sizeof(sev.reason)-1);
   545→
   546→    event_t ev = {
   547→        .type    = EVENT_SLASH,
   548→        .payload = &sev
   549→    };
   550→    event_bus_publish(ctx->bus, &ev);
   551→
   552→    return 0;
   553→}
