   121→/*
   122→ * tp_shutdown()
   123→ *   Free processor resources.
   124→ */
   125→void tp_shutdown(txp_ctx_t **pctx)
   126→{
   127→    if (!pctx || !*pctx) return;
   128→
   129→    txp_ctx_t *ctx = *pctx;
   130→
   131→    pthread_mutex_destroy(&ctx->mtx);
   132→    free(ctx);
   133→    *pctx = NULL;
   134→
   135→    log_info("Transaction Processor shutdown complete.");
   136→}
