   138→/*
   139→ * tp_process()
   140→ *   Entry-point for one transaction.  Thread-safe.
   141→ *
   142→ *   Returns:
   143→ *     0  – transaction accepted & applied
   144→ *    >0 – transaction rejected (status code defined below)
   145→ *    <0 – fatal/internal error
   146→ */
   147→int tp_process(txp_ctx_t *ctx, const uint8_t *raw, size_t raw_len)
   148→{
   149→    if (!ctx || !raw || !raw_len) {
   150→        return -EINVAL;
   151→    }
   152→
   153→    /* Decode/deserialize */
   154→    tx_t tx;
   155→    memset(&tx, 0, sizeof(tx));
   156→    if (tx_decode(&tx, raw, raw_len) != 0) {
   157→        log_debug("tp_process: failed to decode transaction (len=%zu)", raw_len);
   158→        pthread_mutex_lock(&ctx->mtx);
   159→        ctx->stats.rejected_payload++;
   160→        pthread_mutex_unlock(&ctx->mtx);
   161→        return 4; /* invalid payload */
   162→    }
   163→
   164→    const uint64_t ts_unix = (uint64_t)time(NULL);
   165→    const uint64_t t0_ns   = metrics_now_ns();
   166→
   167→    /* Validation pipeline */
   168→    if (!tp_verify_signature(&tx)) {
   169→        pthread_mutex_lock(&ctx->mtx);
   170→        ctx->stats.rejected_sig++;
   171→        pthread_mutex_unlock(&ctx->mtx);
   172→        return 1; /* bad signature */
   173→    }
   174→    if (!tp_verify_nonce(ctx, &tx)) {
   175→        pthread_mutex_lock(&ctx->mtx);
   176→        ctx->stats.rejected_nonce++;
   177→        pthread_mutex_unlock(&ctx->mtx);
   178→        return 2; /* nonce mismatch */
   179→    }
   180→    if (!tp_verify_funds(ctx, &tx)) {
   181→        pthread_mutex_lock(&ctx->mtx);
   182→        ctx->stats.rejected_balance++;
   183→        pthread_mutex_unlock(&ctx->mtx);
   184→        return 3; /* insufficient funds */
   185→    }
   186→
   187→    /* ── Critical section: apply & emit event ───────────────────────────── */
   188→    if (tp_apply(ctx, &tx, ts_unix) != 0) {
   189→        return -EIO; /* internal error applying */
   190→    }
   191→
   192→    tp_emit_event(ctx, &tx);
   193→    tp_record_metrics(ctx, "accepted", metrics_now_ns() - t0_ns);
   194→
   195→    pthread_mutex_lock(&ctx->mtx);
   196→    ctx->stats.accepted++;
   197→    pthread_mutex_unlock(&ctx->mtx);
   198→
   199→    return 0; /* success */
   200→}
