   202→/* ────────────────────────────────────────────────────────────────────────── */
   203→/* Validation helpers                                                       */
   204→/* ────────────────────────────────────────────────────────────────────────── */
   205→
   206→/*
   207→ * Signature verification
   208→ */
   209→static bool tp_verify_signature(const tx_t *tx)
   210→{
   211→    if (!tx) return false;
   212→
   213→    /* Ed25519 public key & signature size are fixed (32 / 64 bytes) */
   214→    if (tx->sig_len != 64 || tx->pubkey_len != 32) {
   215→        log_debug("tp_verify_signature: malformed key/sig");
   216→        return false;
   217→    }
   218→
   219→    /* Hash the canonicalised, signature-free frame of the transaction */
   220→    uint8_t digest[32];
   221→    if (sha3_256(tx->frame, tx->frame_len, digest) != 0) {
   222→        log_error("tp_verify_signature: sha3_256 failed");
   223→        return false;
   224→    }
   225→
   226→    const bool ok = ed25519_verify(tx->signature, digest, sizeof(digest),
   227→                                   tx->pubkey);
   228→    if (!ok) {
   229→        log_debug("tp_verify_signature: invalid signature for tx %s", tx->tx_id);
   230→    }
   231→    return ok;
   232→}
   233→
   234→/*
   235→ * Nonce verification
   236→ *   Protects against replay and preserves causal order per-account.
   237→ */
   238→static bool tp_verify_nonce(txp_ctx_t *ctx, const tx_t *tx)
   239→{
   240→    account_state_t acct;
   241→    if (ledger_get_account_state(ctx->ledger, tx->from, &acct) != 0) {
   242→        log_debug("tp_verify_nonce: unknown account %s", tx->from);
   243→        return false; /* account must exist */
   244→    }
   245→
   246→    const bool ok = (tx->nonce == acct.next_nonce);
   247→    if (!ok) {
   248→        log_debug("tp_verify_nonce: expected nonce=%" PRIu64 ", got=%" PRIu64,
   249→                  acct.next_nonce, tx->nonce);
   250→    }
   251→    return ok;
   252→}
   253→
   254→/*
   255→ * Balance / funds verification
   256→ */
   257→static bool tp_verify_funds(txp_ctx_t *ctx, const tx_t *tx)
   258→{
   259→    account_state_t acct;
   260→    if (ledger_get_account_state(ctx->ledger, tx->from, &acct) != 0) {
   261→        return false;
   262→    }
   263→
   264→    /* Gas cost: base + payload-dependent */
   265→    const uint64_t gas_cost = tx->gas_price * tx->gas_limit;
   266→    const uint64_t total    = gas_cost + tx->value;
   267→
   268→    const bool ok = (acct.balance >= total);
   269→    if (!ok) {
   270→        log_debug("tp_verify_funds: balance %" PRIu64
   271→                  " < required %" PRIu64 " (gas=%" PRIu64 ", value=%" PRIu64 ")",
   272→                  acct.balance, total, gas_cost, tx->value);
   273→    }
   274→    return ok;
   275→}
