   354→/* ────────────────────────────────────────────────────────────────────────── */
   355→/* Event-Bus integration                                                    */
   356→/* ────────────────────────────────────────────────────────────────────────── */
   357→
   358→static void tp_emit_event(txp_ctx_t *ctx, const tx_t *tx)
   359→{
   360→    event_t ev = {
   361→        .topic = "ledger.tx.applied",
   362→        .ts_unix = (uint64_t)time(NULL)
   363→    };
   364→    snprintf(ev.key, sizeof(ev.key), "%s", tx->tx_id);
   365→
   366→    /* Copy raw transaction as payload; consumer services know how to decode */
   367→    ev.payload     = tx->raw;
   368→    ev.payload_len = tx->raw_len;
   369→
   370→    if (event_bus_publish(ctx->bus, &ev) != 0) {
   371→        log_error("tp_emit_event: failed to publish event for tx %s", tx->tx_id);
   372→    }
   373→}
