   109→/* Hex helper – converts binary to hex string (dst must be >= src_len*2+1) */
   110→static void
   111→bin2hex(const uint8_t *src, size_t src_len, char *dst)
   112→{
   113→    static const char *hex = "0123456789abcdef";
   114→    for (size_t i = 0; i < src_len; ++i) {
   115→        dst[i*2]     = hex[(src[i] >> 4) & 0xF];
   116→        dst[i*2 + 1] = hex[src[i] & 0xF];
   117→    }
   118→    dst[src_len * 2] = '\0';
   119→}
