   132→/* Find artifact by id (requires caller hold read or write lock) */
   133→static artifact_t *
   134→ledger_find(ledger_t *l, const char *artifact_id)
   135→{
   136→    for (artifact_t *cur = l->head; cur; cur = cur->next) {
   137→        if (strncmp(cur->artifact_id, artifact_id, sizeof(cur->artifact_id)) == 0)
   138→            return cur;
   139→    }
   140→    return NULL;
   141→}
