   143→/* Upsert artifact record based on incoming tx */
   144→static bool
   145→ledger_apply_tx(ledger_t *l, const tx_t *tx)
   146→{
   147→    bool result = false;
   148→
   149→    pthread_rwlock_wrlock(&l->lock);
   150→
   151→    /* Determine artifact id. For simplicity we reuse tx_id. */
   152→    artifact_t *art = ledger_find(l, tx->tx_id);
   153→
   154→    if (!art) {
   155→        /* New artifact */
   156→        art = calloc(1, sizeof(*art));
   157→        if (!art) {
   158→            pthread_rwlock_unlock(&l->lock);
   159→            return false;
   160→        }
   161→
   162→        strncpy(art->artifact_id, tx->tx_id, sizeof(art->artifact_id) - 1);
   163→        art->metadata = json_deep_copy(tx->payload); /* may be NULL */
   164→        art->state = tx->new_state;
   165→        art->last_update = epoch_sec();
   166→        art->next = l->head;
   167→        l->head = art;
   168→        result = true;
   169→    } else {
   170→        /* State transition rules could be enforced here (omitted) */
   171→        art->state = tx->new_state;
   172→        art->last_update = epoch_sec();
   173→
   174→        if (art->metadata)
   175→            json_decref(art->metadata);
   176→
   177→        art->metadata = json_deep_copy(tx->payload);
   178→        result = true;
   179→    }
   180→
   181→    pthread_rwlock_unlock(&l->lock);
   182→    return result;
   183→}
