   185→static void
   186→ledger_free(ledger_t *l)
   187→{
   188→    pthread_rwlock_wrlock(&l->lock);
   189→    artifact_t *cur = l->head;
   190→    while (cur) {
   191→        artifact_t *next = cur->next;
   192→        if (cur->metadata)
   193→            json_decref(cur->metadata);
   194→        free(cur);
   195→        cur = next;
   196→    }
   197→    l->head = NULL;
   198→    pthread_rwlock_unlock(&l->lock);
   199→    pthread_rwlock_destroy(&l->lock);
   200→}
