1→/**
     2→ * HoloCanvas LedgerCore – Block Management API
     3→ * ------------------------------------------------------------
     4→ * This header exposes a production-quality Block abstraction for
     5→ * HoloCanvas’ micro-gallery blockchain.  It provides:
     6→ *   • Canonical block/merkle-root hashing (double-SHA-256)
     7→ *   • Dynamic transaction aggregation
     8→ *   • Binary (de)serialization helpers
     9→ *   • Memory-safe construction / destruction helpers
    10→ *
    11→ * The API is delivered as a single-file header.  To include the
    12→ * implementation in exactly one translation unit, define
    13→ *
    14→ *      #define BLOCK_IMPLEMENTATION
    15→ *
    16→ * before including this file.
    17→ *
    18→ * Dependencies:
    19→ *   – OpenSSL (or compatible) for SHA-256
    20→ *   – Standard C11 headers
    21→ *
    22→ * NOTE: The LedgerCore transaction API is forward-declared and must
    23→ *       be linked from the `transaction` module.
    24→ */
    25→
    26→#ifndef HOLOCANVAS_LEDGER_CORE_BLOCK_H
    27→#define HOLOCANVAS_LEDGER_CORE_BLOCK_H
    28→
    29→#ifdef __cplusplus
    30→extern "C" {
    31→#endif
    32→
    33→/* ----------  Standard C & System Includes  ---------- */
    34→#include <stdint.h>
    35→#include <stddef.h>
    36→#include <stdbool.h>
    37→#include <time.h>
    38→
    39→/* ----------  Public Constants  ---------- */
    40→#define BLOCK_HASH_SIZE         32      /* SHA-256 */
    41→#define BLOCK_DEFAULT_VERSION   0x0001
    42→#define BLOCK_MAX_TX            8192    /* soft-cap guard */
    43→
    44→/* ----------  Error Codes  ---------- */
    45→typedef enum {
    46→    BLOCK_SUCCESS            =  0,
    47→    BLOCK_ERR_MEM            = -1,
    48→    BLOCK_ERR_PARAM          = -2,
    49→    BLOCK_ERR_TX_LIMIT       = -3,
    50→    BLOCK_ERR_SERIALIZATION  = -4,
    51→    BLOCK_ERR_HASH           = -5,
    52→    BLOCK_ERR_VALIDATION     = -6
    53→} block_err_t;
    54→
    55→/* ----------  Forward Declarations  ---------- */
    56→struct ledger_tx;  /* Opaque transaction type handled by LedgerCore */
    57→
    58→/* LedgerCore transaction helper prototypes (implemented elsewhere) */
    59→int  ledger_tx_hash      (const struct ledger_tx *tx,
    60→                          uint8_t hash_out[BLOCK_HASH_SIZE]);
    61→int  ledger_tx_serialize (const struct ledger_tx *tx,
    62→                          uint8_t **buf_out, size_t *len_out);
    63→int  ledger_tx_deserialize(const uint8_t *buf, size_t buf_len,
    64→                           struct ledger_tx **tx_out);
    65→void ledger_tx_free      (struct ledger_tx *tx);
    66→
    67→/* ----------  Type Definitions  ---------- */
    68→/* Block header (wire format) */
    69→typedef struct {
    70→    uint32_t version;                              /* always little-endian in-memory */
    71→    uint8_t  prev_hash[BLOCK_HASH_SIZE];
    72→    uint8_t  merkle_root[BLOCK_HASH_SIZE];
    73→    uint64_t timestamp;                            /* UNIX epoch (sec) */
    74→    uint32_t bits;                                 /* difficulty target */
    75→    uint32_t nonce;
    76→} block_header_t;
    77→
    78→/* Full block object (in-memory) */
    79→typedef struct {
    80→    /* Header (must remain the first member!) */
    81→    block_header_t header;
    82→
    83→    /* Chain-position metadata (not serialized) */
    84→    uint64_t height;
    85→
    86→    /* Dynamic transaction list */
    87→    struct ledger_tx **txs;
    88→    size_t   tx_count;
    89→    size_t   tx_capacity;      /* internal capacity */
    90→
    91→    /* Cached header hash (double-SHA-256) */
    92→    uint8_t  hash[BLOCK_HASH_SIZE];
    93→    bool     hash_valid;
    94→
    95→    bool     finalized;        /* true after block_finalize() */
    96→} block_t;
    97→
    98→
    99→/* ----------  Public API  ---------- */
   100→
   101→/**
   102→ * block_init
   103→ * Initialize an empty block with the given previous-block hash and height.
   104→ * `prev_hash` may be NULL for the genesis block.
   105→ */
   106→int block_init(block_t            *blk,
   107→               const uint8_t       prev_hash[BLOCK_HASH_SIZE],
   108→               uint64_t            height,
   109→               uint32_t            bits);
   110→
   111→/**
   112→ * block_add_tx
   113→ * Append a transaction to the block (O(1) amortized).
   114→ * The block assumes ownership of `tx`.
   115→ */
   116→int block_add_tx(block_t *blk, struct ledger_tx *tx);
   117→
   118→/**
   119→ * block_finalize
   120→ * Compute the Merkle root and the block hash.
   121→ * After finalization the block is considered immutable.
   122→ */
   123→int block_finalize(block_t *blk);
   124→
   125→/**
   126→ * block_validate
   127→ * Sanity-check a block and all of its transactions.
   128→ * (cryptographic signature verification is delegated to the tx layer).
   129→ */
   130→int block_validate(const block_t *blk);
   131→
   132→/**
   133→ * block_serialize / block_deserialize
   134→ * Convert between binary on-wire representation and in-memory struct.
   135→ * Caller owns the returned buffer from serialize(), must free().
   136→ */
   137→int block_serialize  (const block_t *blk,
   138→                      uint8_t **buf_out, size_t *len_out);
   139→int block_deserialize(const uint8_t *buf, size_t buf_len,
   140→                      block_t *blk_out);
   141→
   142→/**
   143→ * block_free
   144→ * Release all heap memory associated with the block.
   145→ */
   146→void block_free(block_t *blk);
   147→
   148→#ifdef __cplusplus
   149→} /* extern "C" */
   150→#endif
   151→
   152→/* ------------------------------------------------------------------------- */
   153→/*                       — Implementation Section —                          */
   154→/* ------------------------------------------------------------------------- */
   155→#ifdef BLOCK_IMPLEMENTATION
   156→/* ----------  Private Helper Utilities  ---------- */
   157→#include <stdlib.h>
   158→#include <string.h>
   159→#include <stdio.h>
   160→#include <arpa/inet.h>   /* for htonl / ntohl */
   161→#include <openssl/sha.h> /* OpenSSL SHA-256   */
   162→
   163→#define _BLOCK_MIN_TX_CAPACITY  8
   164→#define _BLOCK_GROWTH_FACTOR    2
   165→
   166→/* Varint helpers (Bitcoin-style, compactSize) */
   167→static size_t _varint_encoded_size(uint64_t v)
   168→{
   169→    if (v < 0xFDULL)             return 1;
   170→    else if (v <= 0xFFFFULL)     return 3;
   171→    else if (v <= 0xFFFFFFFFULL) return 5;
   172→    else                         return 9;
   173→}
   174→
   175→static uint8_t *_varint_write(uint8_t *dst, uint64_t v)
   176→{
   177→    if (v < 0xFDULL) {
   178→        *dst++ = (uint8_t)v;
   179→    } else if (v <= 0xFFFFULL) {
   180→        *dst++ = 0xFD;
   181→        uint16_t le = (uint16_t)v;
   182→        memcpy(dst, &le, sizeof(le));
   183→        dst += sizeof(le);
   184→    } else if (v <= 0xFFFFFFFFULL) {
   185→        *dst++ = 0xFE;
   186→        uint32_t le = (uint32_t)v;
   187→        memcpy(dst, &le, sizeof(le));
   188→        dst += sizeof(le);
   189→    } else {
   190→        *dst++ = 0xFF;
   191→        uint64_t le = v;
   192→        memcpy(dst, &le, sizeof(le));
   193→        dst += sizeof(le);
   194→    }
   195→    return dst;
   196→}
   197→
   198→static const uint8_t *_varint_read(const uint8_t *src,
   199→                                   const uint8_t *end,
   200→                                   uint64_t *v_out)
   201→{
   202→    if (src >= end) return NULL;
   203→    uint8_t prefix = *src++;
   204→    if (prefix < 0xFDU) {
   205→        *v_out = prefix;
   206→        return src;
   207→    } else if (prefix == 0xFD) {
   208→        if (src + 2 > end) return NULL;
   209→        uint16_t le;
   210→        memcpy(&le, src, 2); src += 2;
   211→        *v_out = le;
   212→    } else if (prefix == 0xFE) {
   213→        if (src + 4 > end) return NULL;
   214→        uint32_t le;
   215→        memcpy(&le, src, 4); src += 4;
   216→        *v_out = le;
   217→    } else {
   218→        if (src + 8 > end) return NULL;
   219→        uint64_t le;
   220→        memcpy(&le, src, 8); src += 8;
   221→        *v_out = le;
   222→    }
   223→    return src;
   224→}
   225→
   226→/* Compute double-SHA-256 */
   227→static void _sha256d(const uint8_t *data, size_t len,
   228→                     uint8_t hash_out[BLOCK_HASH_SIZE])
   229→{
   230→    uint8_t tmp[SHA256_DIGEST_LENGTH];
   231→    SHA256(data, len, tmp);
   232→    SHA256(tmp, sizeof(tmp), hash_out);
   233→}
   234→
   235→/* Merkle root calculation (simple, iterative) */
   236→static int _merkle_root(struct ledger_tx **txs, size_t n,
   237→                        uint8_t root_out[BLOCK_HASH_SIZE])
   238→{
   239→    if (n == 0 || txs == NULL) return BLOCK_ERR_PARAM;
   240→
   241→    /* Allocate scratch space for level hashing */
   242→    uint8_t (*hashes)[BLOCK_HASH_SIZE] = malloc(n * BLOCK_HASH_SIZE);
   243→    if (!hashes) return BLOCK_ERR_MEM;
   244→
   245→    /* Seed with transaction hashes */
   246→    for (size_t i = 0; i < n; ++i) {
   247→        if (ledger_tx_hash(txs[i], hashes[i]) != 0) {
   248→            free(hashes);
   249→            return BLOCK_ERR_HASH;
   250→        }
   251→    }
   252→
   253→    size_t level_count = n;
   254→    while (level_count > 1) {
   255→        size_t next_count = (level_count + 1) / 2;
   256→        for (size_t i = 0; i < next_count; ++i) {
   257→            /* Duplicate last hash if odd number */
   258→            const uint8_t *left  = hashes[i * 2];
   259→            const uint8_t *right = (i * 2 + 1 < level_count)
   260→                                   ? hashes[i * 2 + 1]
   261→                                   : hashes[i * 2];
   262→            uint8_t concat[BLOCK_HASH_SIZE * 2];
   263→            memcpy(concat, left,  BLOCK_HASH_SIZE);
   264→            memcpy(concat + BLOCK_HASH_SIZE, right, BLOCK_HASH_SIZE);
   265→            _sha256d(concat, sizeof(concat), hashes[i]);
   266→        }
   267→        level_count = next_count;
   268→    }
   269→    memcpy(root_out, hashes[0], BLOCK_HASH_SIZE);
   270→    free(hashes);
   271→    return BLOCK_SUCCESS;
   272→}
   273→
   274→/* Block header hashing */
   275→static void _compute_block_hash(const block_header_t *hdr,
   276→                                uint8_t hash_out[BLOCK_HASH_SIZE])
   277→{
   278→    _sha256d((const uint8_t *)hdr, sizeof(*hdr), hash_out);
   279→}
   280→
   281→/* ----------  Public API Implementations  ---------- */
   282→int block_init(block_t            *blk,
   283→               const uint8_t       prev_hash[BLOCK_HASH_SIZE],
   284→               uint64_t            height,
   285→               uint32_t            bits)
   286→{
   287→    if (!blk) return BLOCK_ERR_PARAM;
   288→    memset(blk, 0, sizeof(*blk));
   289→
   290→    blk->header.version = BLOCK_DEFAULT_VERSION;
   291→
   292→    if (prev_hash)
   293→        memcpy(blk->header.prev_hash, prev_hash, BLOCK_HASH_SIZE);
   294→
   295→    blk->header.timestamp = (uint64_t)time(NULL);
   296→    blk->header.bits      = bits;
   297→    blk->header.nonce     = 0;          /* mined later */
   298→
   299→    blk->height       = height;
   300→    blk->tx_capacity  = _BLOCK_MIN_TX_CAPACITY;
   301→    blk->txs          = calloc(blk->tx_capacity, sizeof(struct ledger_tx *));
   302→    if (!blk->txs) return BLOCK_ERR_MEM;
   303→
   304→    return BLOCK_SUCCESS;
   305→}
   306→
   307→int block_add_tx(block_t *blk, struct ledger_tx *tx)
   308→{
   309→    if (!blk || !tx) return BLOCK_ERR_PARAM;
   310→    if (blk->finalized) return BLOCK_ERR_VALIDATION;
   311→    if (blk->tx_count >= BLOCK_MAX_TX) return BLOCK_ERR_TX_LIMIT;
   312→
   313→    /* Grow capacity if needed */
   314→    if (blk->tx_count == blk->tx_capacity) {
   315→        size_t new_cap = blk->tx_capacity * _BLOCK_GROWTH_FACTOR;
   316→        if (new_cap == 0) new_cap = _BLOCK_MIN_TX_CAPACITY;
   317→        struct ledger_tx **new_arr = realloc(blk->txs,
   318→                                    new_cap * sizeof(struct ledger_tx *));
   319→        if (!new_arr) return BLOCK_ERR_MEM;
   320→        blk->txs = new_arr;
   321→        blk->tx_capacity = new_cap;
   322→    }
   323→
   324→    blk->txs[blk->tx_count++] = tx;
   325→    blk->hash_valid = false;
   326→    return BLOCK_SUCCESS;
   327→}
   328→
   329→int block_finalize(block_t *blk)
   330→{
   331→    if (!blk) return BLOCK_ERR_PARAM;
   332→    if (blk->finalized) return BLOCK_SUCCESS;
   333→    if (blk->tx_count == 0) return BLOCK_ERR_VALIDATION;
   334→
   335→    int rc = _merkle_root(blk->txs, blk->tx_count, blk->header.merkle_root);
   336→    if (rc != BLOCK_SUCCESS) return rc;
   337→
   338→    _compute_block_hash(&blk->header, blk->hash);
   339→    blk->hash_valid = true;
   340→    blk->finalized  = true;
   341→    return BLOCK_SUCCESS;
   342→}
   343→
   344→int block_validate(const block_t *blk)
   345→{
   346→    if (!blk || !blk->finalized) return BLOCK_ERR_PARAM;
   347→
   348→    /* Validate merkle root */
   349→    uint8_t root[BLOCK_HASH_SIZE];
   350→    int rc = _merkle_root((struct ledger_tx **)blk->txs,
   351→                          blk->tx_count, root);
   352→    if (rc != BLOCK_SUCCESS) return rc;
   353→    if (memcmp(root, blk->header.merkle_root, BLOCK_HASH_SIZE) != 0)
   354→        return BLOCK_ERR_VALIDATION;
   355→
   356→    /* Validate cached hash */
   357→    uint8_t calc_hash[BLOCK_HASH_SIZE];
   358→    _compute_block_hash(&blk->header, calc_hash);
   359→    if (memcmp(calc_hash, blk->hash, BLOCK_HASH_SIZE) != 0)
   360→        return BLOCK_ERR_HASH;
   361→
   362→    /* Validate each transaction (delegated) */
   363→    for (size_t i = 0; i < blk->tx_count; ++i) {
   364→        /* Transaction-level validation stub.
   365→         * ledger_tx_validate() could be invoked here if available. */
   366→        (void)i;
   367→    }
   368→    return BLOCK_SUCCESS;
   369→}
   370→
   371→int block_serialize(const block_t *blk,
   372→                    uint8_t **buf_out, size_t *len_out)
   373→{
   374→    if (!blk || !buf_out || !len_out) return BLOCK_ERR_PARAM;
   375→    if (!blk->finalized) return BLOCK_ERR_VALIDATION;
   376→
   377→    /* First determine required buffer size */
   378→    size_t size = sizeof(block_header_t);
   379→    size += _varint_encoded_size(blk->tx_count);
   380→
   381→    for (size_t i = 0; i < blk->tx_count; ++i) {
   382→        uint8_t *tx_buf = NULL; size_t tx_len = 0;
   383→        if (ledger_tx_serialize(blk->txs[i], &tx_buf, &tx_len) != 0)
   384→            return BLOCK_ERR_SERIALIZATION;
   385→        size += _varint_encoded_size(tx_len) + tx_len;
   386→        free(tx_buf); /* length only */
   387→    }
   388→
   389→    uint8_t *buf = malloc(size);
   390→    if (!buf) return BLOCK_ERR_MEM;
   391→    uint8_t *ptr = buf;
   392→
   393→    /* Header */
   394→    memcpy(ptr, &blk->header, sizeof(blk->header));
   395→    ptr += sizeof(blk->header);
   396→
   397→    /* Transaction list length */
   398→    ptr = _varint_write(ptr, blk->tx_count);
   399→
   400→    /* Transactions */
